parameters.jsCode:
// Single source of truth for Atlassian endpoints used by this workflow.
// Reads two env vars off the n8n container:
//
//   JIRA_DOMAIN   — host portion only, e.g. '0xdc.atlassian.net'. Used for
//                   human-facing browse URLs in comments etc.
//   JIRA_CLOUD_ID — UUID returned by https://<JIRA_DOMAIN>/_edge/tenant_info.
//                   Stable per workspace.
//
// boardId is intentionally NOT taken from env. Boards are per-project, and
// hardcoding a single boardId would force a 1:1 n8n-instance-to-project
// binding. Instead the workflow resolves it at runtime from each Epic's
// project key (see 'Jira — list boards for project' + 'Pick board for project'
// later in the pipeline). The first kanban board returned for a given
// projectKey is used; if you need per-project board pinning, extend that
// node to also consult a workflow-static-data cache (TODO comment lives there).
//
// All REST calls go through `apiBase` = https://api.atlassian.com/ex/jira/<id>,
// NOT through https://<JIRA_DOMAIN>. This is required because Atlassian service
// accounts can only mint scoped API tokens, and scoped tokens 401 on the
// workspace domain — they only authenticate against the api.atlassian.com
// gateway. See:
//   https://support.atlassian.com/atlassian-cloud/kb/401-unauthorized-error-when-service-account-accesses-jira-or-confluence-api/
//
// n8n 2.21+ runs Code nodes in an isolated Task Runner where `process` is not
// in scope; env vars come in via the `$env` global. The container must also
// have N8N_BLOCK_ENV_ACCESS_IN_NODE=false (set in docker-compose.yml) for
// $env to surface anything.

const host = typeof $env.JIRA_DOMAIN === 'string' ? $env.JIRA_DOMAIN.trim() : '';
if (!host) {
  throw new Error('JIRA_DOMAIN env var is not set on the n8n container, or N8N_BLOCK_ENV_ACCESS_IN_NODE is still true. Check awp-n8n/.env and docker-compose.yml, then restart the container.');
}
if (host.startsWith('http://') || host.startsWith('https://')) {
  throw new Error('JIRA_DOMAIN should be the host only (e.g. mycompany.atlassian.net), without scheme. Got: ' + host);
}

const cloudId = typeof $env.JIRA_CLOUD_ID === 'string' ? $env.JIRA_CLOUD_ID.trim() : '';
if (!cloudId) {
  throw new Error('JIRA_CLOUD_ID env var is not set on the n8n container. Get it via:  curl -s https://' + host + '/_edge/tenant_info  and put the cloudId field into awp-n8n/.env.');
}
if (!/^[0-9a-f-]{36}$/i.test(cloudId)) {
  throw new Error('JIRA_CLOUD_ID does not look like a UUID. Got: ' + cloudId);
}

return [{
  json: {
    workspace: host,
    domain: 'https://' + host,
    cloudId,
    apiBase: 'https://api.atlassian.com/ex/jira/' + cloudId,
  },
}];

