parameters.jsCode:
// Split the Atlassian POST /rest/api/3/search/jql response into one item
// per Epic. Input shape: a single item whose json.issues is the array of
// Epics. Workspace domain comes via cross-node ref to `Set Jira workspace`.
//
// The PM system prompt is baked into this node at sync time by the awp-sync
// sidecar: the INCLUDE marker below (matches /\{\{INCLUDE:[^}]+\}\}/) is
// replaced with a JS string literal containing the prompt file's contents.
// We don't use n8n's Read File node because n8n 2.21+ runs Code nodes in a
// Task Runner where cross-node binary access (binaryDataMode=filesystem)
// hands you a lazy reference without the actual bytes — useless inside the
// sandbox. The bake-at-sync-time pattern keeps system.xml as the source
// of truth: edit the file, re-run `docker compose run --rm n8n-import`,
// and the new prompt is live.
//
// Output: N items, one per Epic, each carrying everything downstream
// nodes need:
//   - epic: the Epic JSON the PM Agent reasons on
//   - domain: 'https://<workspace>.atlassian.net' (for HTTP Request URLs)
//   - systemPrompt: utf-8 of the PM prompt file (inlined at sync time)
//   - userMessage: pre-built JSON the langchain Agent feeds to Sonnet

const systemPrompt = {{INCLUDE:agents/pm/prompts/system.xml}};

const item = $input.first();
const response = (item && item.json) || {};
const issues = Array.isArray(response.issues) ? response.issues : [];

const wsItem = $('Set Jira workspace').first();
const domain = wsItem && wsItem.json && wsItem.json.domain;
const apiBase = wsItem && wsItem.json && wsItem.json.apiBase;
if (!domain || !apiBase) {
  throw new Error('Could not read domain/apiBase from Set Jira workspace node.');
}

// Atlassian's REST v2 returns description as a plain string (wiki markup or
// plain text). REST v3 returns it as an ADF (Atlassian Document Format)
// tree — an object we'd otherwise stringify to '[object Object]' or lose.
// This helper walks an ADF tree and concatenates every `text` leaf, which
// is good enough to feed PM (we don't need formatting fidelity here).
function adfToText(node) {
  if (node == null) return '';
  if (typeof node === 'string') return node;
  if (Array.isArray(node)) return node.map(adfToText).join('');
  if (typeof node === 'object') {
    let out = '';
    if (typeof node.text === 'string') out += node.text;
    if (Array.isArray(node.content)) out += adfToText(node.content);
    if (node.type === 'paragraph' || node.type === 'heading' || node.type === 'bulletList' || node.type === 'orderedList' || node.type === 'listItem') {
      out += '\n';
    }
    return out;
  }
  return '';
}

// Resolve the human "author" we credit (and @mention) in the PM-rewrite audit
// comment. Logic: scan the Epic's changelog (which we asked for via the
// search's `expand=changelog` parameter) for the most recent `description`
// edit AUTHORED BY A HUMAN; the author of that edit is who PM is paraphrasing.
// We skip changelog entries authored by any AWP service account, otherwise
// PM ends up self-mentioning on every re-run: PM's own description PUT is
// always the most recent description edit. If no human description edit
// exists yet (common case for a fresh Epic), fall back to `fields.creator`.
// If even creator is missing or is itself a service account, return null and
// the audit-comment node will degrade to the generic "by the human" wording.
//
// IMPORTANT: keep AWP_SERVICE_ACCOUNT_IDS in sync with
// awp-agents/agents/shared/jira-accounts.yaml. When we add new roles, their
// accountIds belong here too — otherwise we'll erroneously @-mention the new
// AI agent in audit comments.
const AWP_SERVICE_ACCOUNT_IDS = new Set([
  '712020:5a2a8ccc-e479-49a1-9965-2748d01d9d26', // awp-pm
  '712020:88195866-6d79-4da8-a642-e559cd055709', // awp-dev
  '712020:3643c5de-b750-4046-908d-0bc55051ad03', // awp-qa
  '712020:4e757014-d33f-4d1e-acf4-1c0eb3c2848f', // awp-devops
]);

function isHumanAccountId(accountId) {
  return !!accountId && !AWP_SERVICE_ACCOUNT_IDS.has(accountId);
}

function resolveAuthor(epic) {
  const histories = (epic.changelog && Array.isArray(epic.changelog.histories)) ? epic.changelog.histories : [];
  // histories arrive oldest-first; walk in reverse to find the LAST description edit by a human.
  for (let i = histories.length - 1; i >= 0; i--) {
    const h = histories[i];
    const items = Array.isArray(h.items) ? h.items : [];
    if (!items.some(it => it.field === 'description' || it.fieldId === 'description')) continue;
    const a = h.author || {};
    if (isHumanAccountId(a.accountId)) {
      return { accountId: a.accountId, displayName: a.displayName || '' };
    }
  }
  // No human description edit found — fall back to the original creator,
  // but only if they are themselves human (avoids self-tagging when an AI
  // role files the Epic, e.g. future architect-PM creating sub-Epics).
  const c = epic.fields && epic.fields.creator;
  if (c && isHumanAccountId(c.accountId)) return { accountId: c.accountId, displayName: c.displayName || '' };
  return null;
}

const out = [];
for (const epic of issues) {
  const rawDesc = epic.fields?.description;
  let description = '';
  if (typeof rawDesc === 'string') {
    description = rawDesc;
  } else if (rawDesc && typeof rawDesc === 'object') {
    description = adfToText(rawDesc).trim();
  }

  const projectKey = epic.fields?.project?.key || (epic.key || '').split('-')[0] || '';
  const author = resolveAuthor(epic);
  out.push({
    json: {
      epic: {
        key: epic.key,
        id: epic.id,
        summary: epic.fields?.summary || '',
        description,
        projectKey,
        author,
      },
      domain,
      apiBase,
      systemPrompt,
      userMessage: JSON.stringify({
        epic: {
          key: epic.key,
          summary: epic.fields?.summary || '',
          description,
        },
      }),
    },
  });
}

return out;

// Parse PM's <output>...</output> block and split into two execution paths:
//   - stories     : N items, one per Story to be created
//   - clarification: 1 item carrying the questions list
//
// Hardcoded maps below MUST stay in sync with:
//   awp-agents/agents/shared/jira-accounts.yaml  (accountId per role)
//   awp-agents/agents/shared/jira-fields.yaml    (customfield_NNNNN per semantic key)
// When you change either yaml, update this Code node too.
//
// `description` is converted from Markdown to ADF (Atlassian Document Format)
// because we POST Stories via /rest/api/3/issue. Jira's v2 endpoint took
// description as a plain string interpreted as wiki markup, which mangled
// PM's Markdown (`## Heading` rendered as a literal numbered list, bullet
// points nested inside the heading, etc.). v3 takes ADF, an explicit JSON
// tree of structural nodes — no parsing ambiguity. The converter below is
// deliberately small: it handles paragraphs, headings (h1-h6), and bullet
// lists, which cover everything PM emits per the system prompt. Anything
// fancier (tables, inline bold/italic) we don't ask PM for; if we ever do,
// extend the converter, don't try to push Markdown straight through.
function mdToAdf(md) {
  const text = typeof md === 'string' ? md : '';
  const lines = text.split('\n');
  const content = [];
  let listBuf = null;
  let paraBuf = [];

  const flushPara = () => {
    if (paraBuf.length) {
      content.push({
        type: 'paragraph',
        content: [{ type: 'text', text: paraBuf.join(' ') }],
      });
      paraBuf = [];
    }
  };
  const flushList = () => {
    if (listBuf) { content.push(listBuf); listBuf = null; }
  };

  for (const raw of lines) {
    const trimmed = raw.replace(/^\s+|\s+$/g, '');
    const h = trimmed.match(/^(#{1,6})\s+(.+)$/);
    if (h) {
      flushPara(); flushList();
      content.push({
        type: 'heading',
        attrs: { level: h[1].length },
        content: [{ type: 'text', text: h[2] }],
      });
      continue;
    }
    const b = trimmed.match(/^[-*]\s+(.+)$/);
    if (b) {
      flushPara();
      if (!listBuf) listBuf = { type: 'bulletList', content: [] };
      listBuf.content.push({
        type: 'listItem',
        content: [{
          type: 'paragraph',
          content: [{ type: 'text', text: b[1] }],
        }],
      });
      continue;
    }
    if (trimmed === '') {
      flushPara(); flushList();
      continue;
    }
    flushList();
    paraBuf.push(trimmed);
  }
  flushPara(); flushList();
  if (content.length === 0) content.push({ type: 'paragraph' });
  return { type: 'doc', version: 1, content };
}

const ACCOUNT_IDS = {
  dev:    '712020:88195866-6d79-4da8-a642-e559cd055709',
  qa:     '712020:3643c5de-b750-4046-908d-0bc55051ad03',
  devops: '712020:4e757014-d33f-4d1e-acf4-1c0eb3c2848f',
};
const PM_ACCOUNT_ID = '712020:5a2a8ccc-e479-49a1-9965-2748d01d9d26';

const FIELDS = {
  role:                   'customfield_10040',
  tier:                   'customfield_10041',
  acceptance_criteria:    'customfield_10042',
  estimate_input_tokens:  'customfield_10043',
  estimate_output_tokens: 'customfield_10044',
};

const ROLE_OPTIONS = ['dev', 'qa', 'devops'];
const TIER_OPTIONS = ['L1', 'L2', 'L3'];
const MAX_STORIES = 10;

// 1:1 mapping is preserved by the langchain Agent node, so we match by index.
const items = $input.all();
const epics = $('Prep Epic + prompt').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const epic = epics[i]?.json?.epic
            || epics[0]?.json?.epic
            || { key: 'UNKNOWN', summary: '', description: '' };

  // The langchain Agent node returns its final answer under `output`.
  const raw =
    item.json.output
    ?? item.json.text
    ?? item.json.response
    ?? '';

  // Preferred shape per prompt: <output>{...json...}</output>. We accept three
  // fallbacks because instruction-following on Haiku is uneven:
  //   1) <output>...</output> wrapper (strict, ideal).
  //   2) Raw JSON (no wrapper) — strip optional markdown fences first.
  //   3) Markdown ```json ... ``` block anywhere in the response.
  // Anything that doesn't yield a JSON object falls through to clarification
  // with a diagnostic that quotes the raw response.
  const rawStr = String(raw);
  const taggedMatch = rawStr.match(/<output>([\s\S]*?)<\/output>/i);
  let inner = null;
  if (taggedMatch) {
    inner = taggedMatch[1].trim();
  } else {
    const fenceMatch = rawStr.match(/```(?:json)?\s*([\s\S]*?)```/i);
    if (fenceMatch) {
      inner = fenceMatch[1].trim();
    } else {
      const first = rawStr.indexOf('{');
      const last = rawStr.lastIndexOf('}');
      if (first !== -1 && last > first) {
        inner = rawStr.slice(first, last + 1).trim();
      }
    }
  }

  if (!inner) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: [
          "PM did not produce a parseable JSON object. Raw response: " + rawStr.slice(0, 400),
        ],
      },
    });
    continue;
  }

  inner = inner.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(inner);
  } catch (e) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: [
          "PM emitted invalid JSON inside <output>: " + e.message + ". Body: " + inner.slice(0, 400),
        ],
      },
    });
    continue;
  }

  if (parsed.needs_clarification === true) {
    const questions = Array.isArray(parsed.questions) ? parsed.questions.filter(q => typeof q === 'string' && q.trim()) : [];
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: questions.length ? questions : ['PM flagged needs_clarification but produced no questions.'],
      },
    });
    continue;
  }

  if (!Array.isArray(parsed.stories)) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: ['PM output had neither a `stories` array nor `needs_clarification: true`.'],
      },
    });
    continue;
  }

  if (parsed.stories.length === 0) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: ['PM returned zero Stories. Either the Epic is empty or PM could not decompose it.'],
      },
    });
    continue;
  }

  if (parsed.stories.length > MAX_STORIES) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: [
          `PM returned ${parsed.stories.length} Stories, cap is ${MAX_STORIES}. Please descope the Epic so it can be decomposed into 10 or fewer Stories.`,
        ],
      },
    });
    continue;
  }

  // PM should also emit a rewritten Epic description (markdown). It replaces
  // the human author's original text in the Epic; the n8n workflow preserves
  // the original in an audit comment (see `Jira — audit comment on Epic`).
  // If PM omits it (older prompt versions, or model misbehaviour), we skip the
  // description PUT but still create Stories and update token totals — better
  // partial success than failing the whole decomposition.
  const epicDescriptionMd = typeof parsed.epic_description === 'string' ? parsed.epic_description.trim() : '';
  const epicDescriptionAdf = epicDescriptionMd ? mdToAdf(epicDescriptionMd) : null;

  // Validate every story up-front; one bad apple → kick the whole Epic to clarification.
  const issues = [];
  for (const [idx, s] of parsed.stories.entries()) {
    if (typeof s.summary !== 'string' || !s.summary.trim()) issues.push(`story[${idx}].summary missing`);
    if (typeof s.description !== 'string') issues.push(`story[${idx}].description missing`);
    if (typeof s.acceptance_criteria !== 'string' || !s.acceptance_criteria.trim()) issues.push(`story[${idx}].acceptance_criteria missing`);
    if (!ROLE_OPTIONS.includes(s.role)) issues.push(`story[${idx}].role must be one of ${ROLE_OPTIONS.join('|')}, got ${JSON.stringify(s.role)}`);
    if (!TIER_OPTIONS.includes(s.tier)) issues.push(`story[${idx}].tier must be one of ${TIER_OPTIONS.join('|')}, got ${JSON.stringify(s.tier)}`);
    if (typeof s.estimate_input_tokens !== 'number' || s.estimate_input_tokens <= 0) issues.push(`story[${idx}].estimate_input_tokens must be a positive number`);
    if (typeof s.estimate_output_tokens !== 'number' || s.estimate_output_tokens <= 0) issues.push(`story[${idx}].estimate_output_tokens must be a positive number`);
  }
  if (issues.length) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: [
          'PM output failed schema validation. PM must re-emit. Issues: ' + issues.join('; '),
        ],
      },
    });
    continue;
  }

  // Emit one item per Story with a pre-built Jira REST payload. The downstream
  // HTTP node only needs to POST $json.restBody — no expression gymnastics there.
  // We tag every story with its local id so the user can rebuild depends_on
  // links manually later (M2 will add Jira issuelink wiring).
  const domain = epics[i]?.json?.domain || epics[0]?.json?.domain;
  const apiBase = epics[i]?.json?.apiBase || epics[0]?.json?.apiBase;
  const projectKey = epic.projectKey || (epic.key || '').split('-')[0] || '';
  if (!projectKey) {
    out.push({
      json: {
        kind: 'clarification',
        epic,
        questions: ['Could not derive projectKey from Epic. Search node must request the project field; Epic should expose epic.fields.project.key.'],
      },
    });
    continue;
  }
  for (const [idx, s] of parsed.stories.entries()) {
    const role = s.role;
    const tier = s.tier;
    const story = {
      localId: s.id || `s${idx + 1}`,
      summary: s.summary.trim(),
      description: s.description,
      acceptance_criteria: s.acceptance_criteria,
      role,
      tier,
      estimate_input_tokens: Math.round(s.estimate_input_tokens),
      estimate_output_tokens: Math.round(s.estimate_output_tokens),
      depends_on: Array.isArray(s.depends_on) ? s.depends_on : [],
      assigneeAccountId: ACCOUNT_IDS[role],
    };

    // Jira REST v3 create-issue payload.
    //   - Custom select-list fields: { value: "option name" }.
    //   - Number fields: raw integers.
    //   - Top-level `description`: ADF JSON tree (see mdToAdf at the top of
    //     this node).
    //   - `acceptance_criteria` (customfield, type text_multiline): ALSO
    //     ADF in v3. The 'text_multiline' admin label is misleading — Jira
    //     stores it as a Paragraph field whose REST v3 wire format is ADF.
    //     We confirmed empirically: sending a plain string returns
    //     `400 The field value is not valid Atlassian Document Format (ADF)
    //     content.` So we pass it through the same converter as description.
    //   - `parent.key`: links Story to its Epic in team-managed projects.
    //   - `project.key`: whatever project the parent Epic lives in. Workflow
    //     is multi-project aware: PM picks up Epics by `assignee = currentUser()`
    //     across all projects PM is added to, and the resulting Stories land
    //     in the same project as their parent Epic.
    const restBody = {
      fields: {
        project: { key: projectKey },
        issuetype: { name: 'Story' },
        summary: story.summary,
        description: mdToAdf(story.description),
        assignee: { accountId: story.assigneeAccountId },
        parent: { key: epic.key },
        [FIELDS.role]: { value: role },
        [FIELDS.tier]: { value: tier },
        [FIELDS.acceptance_criteria]: mdToAdf(story.acceptance_criteria),
        [FIELDS.estimate_input_tokens]: story.estimate_input_tokens,
        [FIELDS.estimate_output_tokens]: story.estimate_output_tokens,
      },
    };

    out.push({
      json: {
        kind: 'story',
        epic,
        epicDescriptionMd,
        epicDescriptionAdf,
        story,
        fieldIds: FIELDS,
        domain,
        apiBase,
        projectKey,
        restBody,
      },
    });
  }
}

return out;

// Translate PM's `depends_on` declarations into Jira "Blocks" issue-link
// specs, one item per link. Runs in parallel with `One item per Epic` (both
// are fed by `Jira — create Story (REST)`'s N-item output) because they read
// the same upstream cross-node refs but produce orthogonal outputs:
//   - `One item per Epic` collapses to 1 item per Epic for the audit /
//     update / board / transition branches.
//   - This node EXPANDS to N items, one per link to be created.
//
// PM's local ids (`s1`, `s2`, …) are only unique within an Epic, so the map
// is keyed by `<epicKey>::<localId>`. Stories that don't declare a
// `depends_on`, or declare ones we can't resolve (PM hallucinated a sibling
// id that doesn't exist), are silently skipped — better to ship the rest of
// the decomposition than fail the entire Epic. The Code node sits on the
// happy path, so failures here mean ZERO output items and the downstream
// HTTP node is a no-op (n8n treats no-input HTTP nodes as success).
//
// Direction of the Jira link — read this before touching the downstream POST.
// The "Blocks" link type configures inward="is blocked by", outward="blocks".
// Atlassian's support KB famously claims "outwardIssue = the blocker", which
// is WRONG and contradicts both the canonical issue-linking-model docs and
// the official jira-python client. The verifiable contract (matching what
// Jira actually stores and renders):
//   inwardIssue.key  = the BLOCKER  (the issue "to link from", the source).
//   outwardIssue.key = the BLOCKED  (the issue "to link to",   the target).
// Sanity check: when you GET the blocked issue (e.g. THING-1), the link in
// its `issueLinks` array reports the blocker via `inwardIssue: FEAT-1` and
// the UI labels it `type.inward = "is blocked by"` — i.e., the blocker is
// stored at the inward position. We pre-empted that confusion in our naming:
//   blockerKey → goes into POST body as inwardIssue
//   blockedKey → goes into POST body as outwardIssue
// If you ever see links pointing backwards in Jira's UI after editing this
// node, the swap was probably reverted. Re-read this comment before flipping.

const parsed = $('Parse PM output').all();
const created = $('Jira — create Story (REST)').all();

const idToKey = new Map();
let createdIdx = 0;
for (const it of parsed) {
  const j = it.json;
  if (j.kind !== 'story') continue;
  const epicKey = j.epic && j.epic.key;
  const localId = j.story && j.story.localId;
  const jiraKey = created[createdIdx] && created[createdIdx].json && created[createdIdx].json.key;
  if (epicKey && localId && jiraKey) {
    idToKey.set(epicKey + '::' + localId, jiraKey);
  }
  createdIdx++;
}

// Downstream HTTP node pulls `apiBase` via cross-node ref to `Set Jira
// workspace`, so we don't need to thread it through each item here.
const out = [];
for (const it of parsed) {
  const j = it.json;
  if (j.kind !== 'story') continue;
  const epicKey = j.epic && j.epic.key;
  const blockedKey = idToKey.get(epicKey + '::' + (j.story && j.story.localId));
  if (!blockedKey) continue;
  const deps = (j.story && Array.isArray(j.story.depends_on)) ? j.story.depends_on : [];
  for (const dep of deps) {
    const blockerKey = idToKey.get(epicKey + '::' + dep);
    if (!blockerKey || blockerKey === blockedKey) continue;
    out.push({
      json: {
        epicKey,
        blockerKey,
        blockedKey,
        blockerLocalId: dep,
        blockedLocalId: j.story.localId,
      },
    });
  }
}
return out;

// Fold every Story-creation response back into a single item per Epic so
// the downstream Jira nodes (audit comment, board move, transition, Epic
// totals) fire exactly once per Epic instead of once per Story.
//
// Architecture note — why no SplitInBatches loop:
//   We used to wrap `Jira — create Story (REST)` in a SplitInBatches(batchSize=1)
//   loop, but that introduced a subtle data-loss bug: any reference to a
//   node located INSIDE the loop body, when read from OUTSIDE the loop via
//   `$('NodeName').all()`, returns only the items from the FINAL iteration,
//   not the accumulated outputs across all iterations. This Code node sits
//   outside the loop, so `$('Jira — create Story (REST)').all()` would
//   return a single-item array (the last Story response), and only that
//   Story would end up in `storyKeys` / be moved to the board — all earlier
//   creations were silently dropped. Removing the loop makes n8n process
//   the N create-Story items serially through a single HTTP node execution
//   pass; that node then emits N outputs, which we collect here. Jira tier-
//   1 rate limit (~10 req/s) easily absorbs 10 stories per Epic per minute
//   so no throttle wrapper is needed.
//
// Inputs we read by cross-node reference:
//   - 'Parse PM output': N items, one per Story, with epic context attached.
//   - 'Jira — create Story (REST)': N items, the Atlassian create responses
//     ({ id, key, self }), aligned 1:1 by index with Parse PM output's
//     `kind === 'story'` items because n8n preserves order through HTTP
//     nodes when processing multiple input items.
//
// Output: one item per distinct Epic, carrying:
//   - epic / domain / apiBase / projectKey context
//   - storyKeys (array of newly created Story keys) and storyCount
//   - inputTokensTotal / outputTokensTotal — sums of PM's per-Story estimates,
//     written back to the parent Epic's `customfield_10043`/`customfield_10044`
//     by a downstream PUT so the Epic shows the total cost preview before any
//     Dev/QA agent picks the Stories up. The same custom fields are reused
//     across issue types: on a Story they hold the Story's own estimate,
//     on an Epic they hold the sum of children.

const parsed = $('Parse PM output').all();
const created = $('Jira — create Story (REST)').all();
const byEpic = new Map();
let createdIdx = 0;
for (const it of parsed) {
  const j = it.json;
  if (j.kind !== 'story') continue;
  const ek = j.epic?.key;
  if (!ek) { createdIdx++; continue; }
  if (!byEpic.has(ek)) {
    byEpic.set(ek, {
      epic: j.epic,
      domain: j.domain,
      apiBase: j.apiBase,
      projectKey: j.projectKey,
      // PM-rewritten Epic description (ADF form, ready for Jira PUT) and the
      // original human-authored text (plain string, ready for an audit
      // comment). Both are per-epic, identical across this Epic's story
      // items, so we capture them on the first sighting.
      epicDescriptionAdf: j.epicDescriptionAdf || null,
      epicOriginalDescription: (j.epic && j.epic.description) || '',
      storyKeys: [],
      inputTokensTotal: 0,
      outputTokensTotal: 0,
    });
  }
  const entry = byEpic.get(ek);
  const createdKey = created[createdIdx]?.json?.key;
  if (createdKey) entry.storyKeys.push(createdKey);
  entry.inputTokensTotal += Math.max(0, Number(j.story?.estimate_input_tokens) || 0);
  entry.outputTokensTotal += Math.max(0, Number(j.story?.estimate_output_tokens) || 0);
  createdIdx++;
}
return Array.from(byEpic.values()).map(v => ({ json: { ...v, storyCount: v.storyKeys.length } }));

