// Pick the right board for the Epic's project. The agile API returns
// every board scoped to a project (often several: kanban + scrum + custom
// JQL boards); we want the kanban one because the rest of the workflow
// assumes Kanban semantics (no sprint API, direct backlog-to-board moves).
//
// `One item per Epic` and this HTTP node both produce one item per Epic in
// the same order — n8n preserves order through HTTP nodes, so item[i] here
// pairs with item[i] from upstream.
//
// Optimization opportunity (deferred): cache resolved boards in
// `$getWorkflowStaticData('global').boardByProject` so we skip the GET
// after the first hit per project. For one or two projects the savings are
// marginal (~50ms per 60s poll) and the IF/Merge plumbing required to do
// conditional fetch isn't worth the workflow complexity right now. Add the
// cache here when the project count climbs.

const httpItems = $input.all();
const upstream = $('One item per Epic').all();
const out = [];
for (let i = 0; i < httpItems.length; i++) {
  const ctx = upstream[i] && upstream[i].json ? upstream[i].json : {};
  const projectKey = ctx.projectKey || '';
  const values = (httpItems[i].json && httpItems[i].json.values) || [];
  const kanban = values.find((b) => b.type === 'kanban');
  const board = kanban || values[0];
  if (!board) {
    throw new Error(`No agile boards returned for project ${projectKey || '(unknown)'}. Check that the project has a Kanban or Scrum board attached, and that awp-pm has read access to it.`);
  }
  out.push({
    json: {
      ...ctx,
      boardId: board.id,
      boardName: board.name,
      boardType: board.type,
    },
  });
}
return out;

// Find the transition that lands on status "In Progress". Atlassian's GET
// transitions endpoint returns the *currently available* transitions for
// the issue, each with `id`, `name`, and `to: { id, name }`. We match on
// `to.name === 'In Progress'` first (most reliable), then fall back to the
// transition's own `name`. If none is found we surface a clear error so the
// user can adjust their workflow (e.g. add an explicit transition into
// In Progress for Epics).

const httpItems = $input.all();
const upstream = $('One item per Epic').all();
const out = [];

for (let i = 0; i < httpItems.length; i++) {
  const transitions = httpItems[i].json.transitions || [];
  const target =
    transitions.find((t) => t.to && t.to.name === 'In Progress') ||
    transitions.find((t) => t.name === 'In Progress');
  const ctx = upstream[i] && upstream[i].json ? upstream[i].json : { epic: { key: 'UNKNOWN' }, domain: '' };
  if (!target) {
    const names = transitions.map((t) => `${t.name} → ${t.to && t.to.name}`).join(', ');
    throw new Error(
      `No \"In Progress\" transition available for ${ctx.epic.key}. Available transitions: ${names || '(none)'}.`
    );
  }
  out.push({
    json: {
      epic: ctx.epic,
      domain: ctx.domain,
      transitionId: target.id,
      transitionName: target.name,
    },
  });
}
return out;
